1	export interface QuoteInput {
2	  items: { type: string }[];
3	}
4	
5	const PROCESSING_FEE = 5;
6	
7	const BLOCK_SIZE = 3;
8	const BLOCK_PRICE = 60;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	export function quote(input: QuoteInput): number {
20	  const countsByType: Record<string, number> = {};
21	  for (const item of input.items) {
22	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
23	  }
24	
25	  let basePremiumTotal = 0;
26	  for (const type of Object.keys(countsByType)) {
27	    const count = countsByType[type];
28	    if (count === BLOCK_SIZE) {
29	      basePremiumTotal += BLOCK_PRICE;
30	    } else {
31	      basePremiumTotal += count * BASE_PREMIUMS[type];
32	    }
33	  }
34	
35	  return basePremiumTotal + PROCESSING_FEE;
36	}
37	
38	export function claim(): number {
39	  return undefined as unknown as number;
40	}
